import{_ as a,o as e,c as r,ag as n}from"./chunks/framework.gU7RhlGX.js";const u=JSON.parse('{"title":"Harness 工程：实现长时间自动开发应用","description":"","frontmatter":{},"headers":[],"relativePath":"Harness Engineering/Harness 工程，实现长时间自动开发应用.md","filePath":"Harness Engineering/Harness 工程，实现长时间自动开发应用.md","lastUpdated":1776422487000}'),l={name:"Harness Engineering/Harness 工程，实现长时间自动开发应用.md"};function i(s,t,o,h,d,g){return e(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="harness-工程-实现长时间自动开发应用" tabindex="-1">Harness 工程：实现长时间自动开发应用 <a class="header-anchor" href="#harness-工程-实现长时间自动开发应用" aria-label="Permalink to &quot;Harness 工程：实现长时间自动开发应用&quot;">​</a></h1><blockquote><p>核心洞察：真正有趣的工作，永远在能力的边界上。模型在进步，边界在移动，寻找下一个有价值的协作架构是关键。</p></blockquote><p>Anthropic 团队在 2026 年分享了他们在 AI 自主编程方面的最新探索：通过设计一套多 AI 协同的 Harness 架构，让 AI 能够持续数小时独立完成全栈应用程序（如数字音频工作站 DAW）的开发。</p><hr><h2 id="_1-单-ai-的-软肋-为什么需要架构" tabindex="-1">1. 单 AI 的“软肋”：为什么需要架构？ <a class="header-anchor" href="#_1-单-ai-的-软肋-为什么需要架构" aria-label="Permalink to &quot;1. 单 AI 的“软肋”：为什么需要架构？&quot;">​</a></h2><p>在复杂的长任务中，单个 AI Agent 往往会遇到以下两个系统性障碍：</p><h3 id="上下文焦虑-context-anxiety" tabindex="-1">上下文焦虑 (Context Anxiety) <a class="header-anchor" href="#上下文焦虑-context-anxiety" aria-label="Permalink to &quot;上下文焦虑 (Context Anxiety)&quot;">​</a></h3><p>当任务处理时间拉长，上下文窗口逐渐填充，模型的表现会显著下降。</p><ul><li><strong>草率收尾</strong>：模型意识到上下文将满，会产生“心理压力”，开始匆忙结束任务或输出半成品代码。</li><li><strong>性能衰减</strong>：长对话背景下模型容易丢失关键指令或架构约束。</li></ul><h3 id="自我评价失真-gratuitous-optimism" tabindex="-1">自我评价失真 (Gratuitous Optimism) <a class="header-anchor" href="#自我评价失真-gratuitous-optimism" aria-label="Permalink to &quot;自我评价失真 (Gratuitous Optimism)&quot;">​</a></h3><p>AI 在评价自己的工作时往往过度乐观。</p><ul><li><strong>主观盲区</strong>：尤其在 UI/UX 设计等缺乏客观标准（如软件测试）的领域，AI 几乎总是给出高分。</li><li><strong>改错动力不足</strong>：由于意识不到缺陷，AI 很难在单人循环中产生高质量的迭代方向。</li></ul><hr><h2 id="_2-三-ai-协作架构-the-squad" tabindex="-1">2. 三 AI 协作架构 (The Squad) <a class="header-anchor" href="#_2-三-ai-协作架构-the-squad" aria-label="Permalink to &quot;2. 三 AI 协作架构 (The Squad)&quot;">​</a></h2><p>为了突破上述瓶颈，Anthropic 采用了一套分工明确的协作系统：</p><table tabindex="0"><thead><tr><th style="text-align:left;">角色</th><th style="text-align:left;">核心职责</th><th style="text-align:left;">关键策略</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>规划者 (Planner)</strong></td><td style="text-align:left;">产品逻辑与高层设计</td><td style="text-align:left;">拒绝微观细节。如果规划太死，错误会随多米诺骨牌传递。只定义交付物，留出执行空间。</td></tr><tr><td style="text-align:left;"><strong>生成者 (Generator)</strong></td><td style="text-align:left;">实际代码编写与实现</td><td style="text-align:left;">模块化实现功能点。配备 Git 进行版本控制，完成后进行自我检查再提交给 QA。</td></tr><tr><td style="text-align:left;"><strong>评估者 (Evaluator)</strong></td><td style="text-align:left;">代码审查与功能 QA</td><td style="text-align:left;">配备 <strong>Playwright MCP</strong>。像真实用户一样点击应用、测试接口和库状态。</td></tr></tbody></table><hr><h2 id="_3-核心工程机制" tabindex="-1">3. 核心工程机制 <a class="header-anchor" href="#_3-核心工程机制" aria-label="Permalink to &quot;3. 核心工程机制&quot;">​</a></h2><h3 id="借鉴-gan-的反馈回路" tabindex="-1">借鉴 GAN 的反馈回路 <a class="header-anchor" href="#借鉴-gan-的反馈回路" aria-label="Permalink to &quot;借鉴 GAN 的反馈回路&quot;">​</a></h3><p>通过将“生成”与“评估”分离，调教一个独立的、极其严格的评估者，比让创作者学会自我批评更容易产生高质量的输出。</p><h3 id="冲刺契约-sprint-contract" tabindex="-1">冲刺契约 (Sprint Contract) <a class="header-anchor" href="#冲刺契约-sprint-contract" aria-label="Permalink to &quot;冲刺契约 (Sprint Contract)&quot;">​</a></h3><p>每一轮功能实现前，生成者与评估者会进行“谈判”，由生成者提出实现路径与验证标准（QA 契约），双方达成一致后才动手，确保目标的一致性。</p><h3 id="上下文重置-context-reset" tabindex="-1">上下文重置 (Context Reset) <a class="header-anchor" href="#上下文重置-context-reset" aria-label="Permalink to &quot;上下文重置 (Context Reset)&quot;">​</a></h3><p>为了彻底解决“上下文焦虑”，团队不再依赖文本压缩，而是直接<strong>清空上下文</strong>：</p><ol><li>启动一个全新的 AI 实例。</li><li>通过一份<strong>结构化交接文档</strong>传递当前状态和下一步计划。</li><li>相当于让精力充沛的“接班人”对照清单继续工作。</li></ol><hr><h2 id="_4-实证案例-从零构建音乐制作软件-daw" tabindex="-1">4. 实证案例：从零构建音乐制作软件 (DAW) <a class="header-anchor" href="#_4-实证案例-从零构建音乐制作软件-daw" aria-label="Permalink to &quot;4. 实证案例：从零构建音乐制作软件 (DAW)&quot;">​</a></h2><p>团队测试了仅通过一句话提示词（“构建一个功能完整的浏览器 DAW”），让三 AI 协作架构自主驱动开发。</p><ul><li><strong>运行时间</strong>：连续工作约 4 小时。</li><li><strong>工程细节</strong>：生成者连续写了 2 小时代码。QA 在反馈中多次抓到了关键功能缺失（如乐器旋钮、EQ 曲线缺失），并驱动生成者完成了“最后一公里”的开发。</li><li><strong>产出结果</strong>：交付了一个包含编曲视图、混音器、播放控制，且能通过自然语言驱动作曲的全栈 React 应用。</li></ul><hr><h2 id="_5-总结-架构的意义" tabindex="-1">5. 总结：架构的意义 <a class="header-anchor" href="#_5-总结-架构的意义" aria-label="Permalink to &quot;5. 总结：架构的意义&quot;">​</a></h2><ul><li><strong>脚手架思维</strong>：模型越强，围绕它的架构就该越精简（不要做多余的约束）。</li><li><strong>边界移动</strong>：模型在进步，但我们要用它去挑战之前根本做不到的更复杂材料。</li><li><strong>工程师的价值</strong>：从过程复盘中寻找灵感，针对真实痛点设计专属的 Harness。</li></ul>',32)])])}const _=a(l,[["render",i]]);export{u as __pageData,_ as default};
